installScript.script:
#!/bin/bash
set -euo pipefail
# Static site (nginx) — serves files the customer uploads to public/. nginx runs
# as the non-root container user, so ALL writable paths (pid, logs, temp) live
# under the data dir, and it listens on the server's allocated port.
mkdir -p /mnt/server/public /mnt/server/tmp/client /mnt/server/tmp/proxy \
  /mnt/server/tmp/fastcgi /mnt/server/tmp/uwsgi /mnt/server/tmp/scgi

if [ ! -f /mnt/server/public/index.html ]; then
  cat > /mnt/server/public/index.html <<'HTML'
<!doctype html>
<html lang="en"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>ReFx Hosting</title>
<style>body{font-family:system-ui,sans-serif;display:grid;place-items:center;min-height:100vh;margin:0;background:#070b12;color:#e6edf3}div{text-align:center;max-width:34rem;padding:2rem}code{background:#11161f;padding:.15rem .4rem;border-radius:.3rem}</style>
</head><body><div>
<h1>🚀 Your ReFx site is live</h1>
<p>Replace this page by uploading your files to <code>public/</code> via SFTP or the file manager.</p>
</div></body></html>
HTML
fi

# nginx config: all temp/pid/log paths under the data dir (writable non-root),
# document root = public/, listening on the allocated port.
cat > /mnt/server/nginx.conf <<EOF
pid /home/container/nginx.pid;
error_log /dev/stderr warn;
events { worker_connections 1024; }
http {
  include /etc/nginx/mime.types;
  default_type application/octet-stream;
  client_body_temp_path /home/container/tmp/client;
  proxy_temp_path /home/container/tmp/proxy;
  fastcgi_temp_path /home/container/tmp/fastcgi;
  uwsgi_temp_path /home/container/tmp/uwsgi;
  scgi_temp_path /home/container/tmp/scgi;
  access_log /dev/stdout;
  sendfile on;
  server {
    listen ${SERVER_PORT:-8080};
    server_name _;
    root /home/container/public;
    index index.html index.htm;
    location / { try_files \$uri \$uri/ =404; }
  }
}
EOF
echo 'Static site (nginx) install complete.'
